 1→import { NextRequest, NextResponse } from "next/server";
 2→import { getStripe } from "@/lib/stripe";
 3→import { db } from "@/lib/db";
 4→import Stripe from "stripe";
 5→
 6→export async function POST(req: NextRequest) {
 7→  const body = await req.text();
 8→  const signature = req.headers.get("stripe-signature");
 9→
10→  if (!signature || !process.env.STRIPE_WEBHOOK_SECRET) {
11→    return NextResponse.json({ error: "Missing signature" }, { status: 400 });
12→  }
13→
14→  let event: Stripe.Event;
15→  try {
16→    event = getStripe().webhooks.constructEvent(
17→      body,
18→      signature,
19→      process.env.STRIPE_WEBHOOK_SECRET
20→    );
21→  } catch (err) {
22→    console.error("Webhook signature verification failed:", err);
23→    return NextResponse.json({ error: "Invalid signature" }, { status: 400 });
24→  }
25→
26→  switch (event.type) {
27→    case "checkout.session.completed": {
28→      const session = event.data.object as Stripe.Checkout.Session;
29→      const userId = session.metadata?.userId;
30→      if (!userId) break;
31→
32→      const subscription = await getStripe().subscriptions.retrieve(
33→        session.subscription as string
34→      );
35→      const sub = subscription as unknown as Record<string, unknown>;
36→
37→      await db.user.update({
38→        where: { id: userId },
39→        data: {
40→          stripeCustomerId: session.customer as string,
41→          stripeSubscriptionId: subscription.id,
42→          stripePriceId: subscription.items.data[0].price.id,
43→          stripeCurrentPeriodEnd: new Date(
44→            (sub.current_period_end as number) * 1000
45→          ),
46→        },
47→      });
48→      break;
49→    }
50→
51→    case "invoice.payment_succeeded": {
52→      const invoiceObj = event.data.object as unknown as Record<string, unknown>;
53→      const rawSub = invoiceObj.subscription;
54→      const subscriptionId =
55→        typeof rawSub === "string"
56→          ? rawSub
57→          : (rawSub as { id?: string } | null)?.id;
58→      if (!subscriptionId) break;
59→
60→      const subscription =
61→        await getStripe().subscriptions.retrieve(subscriptionId);
62→      const sub = subscription as unknown as Record<string, unknown>;
63→
64→      await db.user.updateMany({
65→        where: { stripeSubscriptionId: subscriptionId },
66→        data: {
67→          stripePriceId: subscription.items.data[0].price.id,
68→          stripeCurrentPeriodEnd: new Date(
69→            (sub.current_period_end as number) * 1000
70→          ),
71→        },
72→      });
73→      break;
74→    }
75→
76→    case "customer.subscription.deleted": {
77→      const subscription = event.data.object as Stripe.Subscription;
78→      await db.user.updateMany({
79→        where: { stripeSubscriptionId: subscription.id },
80→        data: {
81→          stripePriceId: null,
82→          stripeSubscriptionId: null,
83→          stripeCurrentPeriodEnd: null,
84→        },
85→      });
86→      break;
87→    }
88→  }
89→
90→  return NextResponse.json({ received: true });
91→}
