 8→// POST /api/sketches — save a sketch
 9→export async function POST(req: NextRequest) {
10→  const ip = req.headers.get("x-forwarded-for") ?? "anonymous";
11→  const { success } = rateLimit(ip);
12→  if (!success) {
13→    return NextResponse.json({ error: "Rate limit exceeded" }, { status: 429 });
14→  }
15→
16→  const session = await auth();
17→  const body = await req.json();
18→  const parsed = createSketchSchema.safeParse(body);
19→
20→  if (!parsed.success) {
21→    return NextResponse.json(
22→      { error: "Invalid sketch data", details: parsed.error.flatten() },
23→      { status: 400 }
24→    );
25→  }
26→
27→  const { title, data, public: isPublic } = parsed.data;
28→  const sanitized = sanitizeSketchData(data);
29→
30→  // If not logged in, only public sketches are allowed
31→  if (!session?.user && isPublic === false) {
32→    return NextResponse.json(
33→      { error: "Sign in to save private sketches" },
34→      { status: 401 }
35→    );
36→  }
37→
38→  const sketch = await db.sketch.create({
39→    data: {
40→      slug: generateSlug(),
41→      title: title ?? "Untitled",
42→      data: JSON.stringify(sanitized),
43→      public: isPublic ?? true,
44→      userId: session?.user?.id ?? null,
45→    },
46→  });
47→
48→  return NextResponse.json({ slug: sketch.slug, id: sketch.id }, { status: 201 });
49→}
