51→// GET /api/sketches — list user's sketches (requires auth)
52→export async function GET() {
53→  const session = await auth();
54→
55→  if (!session?.user?.id) {
56→    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
57→  }
58→
59→  const sketches = await db.sketch.findMany({
60→    where: { userId: session.user.id },
61→    select: {
62→      id: true,
63→      slug: true,
64→      title: true,
65→      public: true,
66→      createdAt: true,
67→      updatedAt: true,
68→    },
69→    orderBy: { updatedAt: "desc" },
70→  });
71→
72→  return NextResponse.json(sketches);
73→}
