 1→const rateLimitMap = new Map<string, { count: number; lastReset: number }>();
 2→
 3→const WINDOW_MS = 60_000; // 1 minute
 4→const MAX_REQUESTS = 60;
 5→
 6→export function rateLimit(identifier: string): { success: boolean; remaining: number } {
 7→  const now = Date.now();
 8→  const record = rateLimitMap.get(identifier);
 9→
10→  if (!record || now - record.lastReset > WINDOW_MS) {
11→    rateLimitMap.set(identifier, { count: 1, lastReset: now });
12→    return { success: true, remaining: MAX_REQUESTS - 1 };
13→  }
14→
15→  if (record.count >= MAX_REQUESTS) {
16→    return { success: false, remaining: 0 };
17→  }
18→
19→  record.count++;
20→  return { success: true, remaining: MAX_REQUESTS - record.count };
21→}
22→
23→// Clean up old entries every 5 minutes
24→if (typeof setInterval !== "undefined") {
25→  setInterval(() => {
26→    const now = Date.now();
27→    for (const [key, record] of rateLimitMap) {
28→      if (now - record.lastReset > WINDOW_MS * 2) {
29→        rateLimitMap.delete(key);
30→      }
31→    }
32→  }, 300_000);
33→}
