 98→  tool: z.enum(["pencil", "ballpoint", "ink"]),
 99→  inkColor: z.string().max(20),
100→  amplitude: z.number().min(0).max(1),
101→  waves: z.number().min(0).max(1),
102→  humanness: z.number().min(0).max(1),
103→  width: z.number().positive().max(5000).optional(),
104→  height: z.number().positive().max(5000).optional(),
105→  elements: z.array(sketchElementSchema).max(1000),
106→});
