125→// Sanitize text content to prevent XSS
126→export function sanitizeSketchData(data: z.infer<typeof sketchDataSchema>) {
127→  return {
128→    ...data,
129→    elements: data.elements.map((el) => {
130→      if ("text" in el && typeof el.text === "string") {
131→        return {
132→          ...el,
133→          text: el.text
134→            .replace(/</g, "&lt;")
135→            .replace(/>/g, "&gt;")
136→            .replace(/"/g, "&quot;")
137→            .replace(/'/g, "&#x27;"),
138→        };
139→      }
140→      if ("label" in el && typeof el.label === "string") {
141→        return {
142→          ...el,
143→          label: el.label
144→            .replace(/</g, "&lt;")
145→            .replace(/>/g, "&gt;"),
146→        };
147→      }
148→      return el;
149→    }),
150→  };
151→}
