 1→/**
 2→ * Plan gate utilities.
 3→ *
 4→ * A user is "pro" when they have an active Stripe subscription
 5→ * (i.e. stripeCurrentPeriodEnd is in the future).
 6→ */
 7→
 8→interface UserLike {
 9→  stripePriceId?: string | null;
10→  stripeSubscriptionId?: string | null;
11→  stripeCurrentPeriodEnd?: Date | string | null;
12→}
13→
14→export function isPro(user: UserLike | null | undefined): boolean {
15→  if (!user?.stripePriceId || !user.stripeCurrentPeriodEnd) return false;
16→  const end =
17→    typeof user.stripeCurrentPeriodEnd === "string"
18→      ? new Date(user.stripeCurrentPeriodEnd)
19→      : user.stripeCurrentPeriodEnd;
20→  return end.getTime() > Date.now();
21→}
22→
23→export function canSavePrivate(user: UserLike | null | undefined): boolean {
24→  return isPro(user);
25→}
26→
27→export function canShare(user: UserLike | null | undefined): boolean {
28→  return isPro(user);
29→}
30→
31→/** Free users: 10 public sketches. Pro: unlimited. */
32→export function getSketchLimit(user: UserLike | null | undefined): number {
33→  return isPro(user) ? Infinity : 10;
34→}
